static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed2dAsymmetricInputAsymmetricKernelCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0); // [N, Cin, Hin, Win]
    const gert::Shape *w_shape = context->GetInputShape(1); // [Cin, Cout, kH, kW]

    const int64_t N  = x_shape->GetDim(0);
    const int64_t Ci = x_shape->GetDim(1);
    const int64_t Hi = x_shape->GetDim(2);
    const int64_t Wi = x_shape->GetDim(3);

    const int64_t W_Ci = w_shape->GetDim(0);
    const int64_t Co   = w_shape->GetDim(1);
    const int64_t kH   = w_shape->GetDim(2);
    const int64_t kW   = w_shape->GetDim(3);

    // Guard simple assumptions: weight.Cin must match input.Cin
    if (W_Ci != Ci) {
        return ge::GRAPH_FAILED;
    }

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *stride_h = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *stride_w = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *pad_t    = attrs->GetAttrPointer<int32_t>(2);
    const int32_t *pad_l    = attrs->GetAttrPointer<int32_t>(3);
    const int32_t *pad_b    = attrs->GetAttrPointer<int32_t>(4);
    const int32_t *pad_r    = attrs->GetAttrPointer<int32_t>(5);
    const int32_t *dilation_h = attrs->GetAttrPointer<int32_t>(6);
    const int32_t *dilation_w = attrs->GetAttrPointer<int32_t>(7);
    const int32_t *groups     = attrs->GetAttrPointer<int32_t>(8);

    const int32_t sH = (stride_h != nullptr) ? *stride_h : 1;
    const int32_t sW = (stride_w != nullptr) ? *stride_w : 1;
    const int32_t pT = (pad_t     != nullptr) ? *pad_t : 0;
    const int32_t pL = (pad_l     != nullptr) ? *pad_l : 0;
    const int32_t pB = (pad_b     != nullptr) ? *pad_b : 0;
    const int32_t pR = (pad_r     != nullptr) ? *pad_r : 0;
    const int32_t dH = (dilation_h!= nullptr) ? *dilation_h : 1;
    const int32_t dW = (dilation_w!= nullptr) ? *dilation_w : 1;
    const int32_t G  = (groups    != nullptr) ? *groups : 1;

    // Compute output spatial size per PyTorch ConvTranspose2d:
    // H_out = (H_in - 1) * sH - (pT + pB) + dH * (kH - 1) + 1 + output_padding (0 here)
    // W_out = (W_in - 1) * sW - (pL + pR) + dW * (kW - 1) + 1 + output_padding (0 here)
    const int64_t Ho = (Hi - 1) * sH - (pT + pB) + dH * (kH - 1) + 1;
    const int64_t Wo = (Wi - 1) * sW - (pL + pR) + dW * (kW - 1) + 1;

    gert::Shape *y_shape = context->GetOutputShape(0);
    y_shape->SetDimNum(4);
    y_shape->SetDim(0, N);
    y_shape->SetDim(1, Co);
    y_shape->SetDim(2, Ho);
    y_shape->SetDim(3, Wo);

    // Choose tile size based on UB budget for storing a simple y tile
    uint32_t maxTile = UB_BUDGET_BYTES / sizeof(float);
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    const uint64_t totalOutElems64 = static_cast<uint64_t>(N) * static_cast<uint64_t>(Co) *
                                     static_cast<uint64_t>(Ho) * static_cast<uint64_t>(Wo);
    uint32_t totalOutElems = static_cast<uint32_t>(totalOutElems64);

    uint32_t tileLen = maxTile;
    if (totalOutElems < tileLen) {
        const uint32_t aligned = AlignDown(totalOutElems, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : totalOutElems;
    }
    const uint32_t numTiles = (tileLen == 0u) ? 1u : CeilDiv(totalOutElems, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_n(static_cast<uint32_t>(N));
    tiling.set_ci(static_cast<uint32_t>(Ci));
    tiling.set_hi(static_cast<uint32_t>(Hi));
    tiling.set_wi(static_cast<uint32_t>(Wi));
    tiling.set_co(static_cast<uint32_t>(Co));
    tiling.set_kh(static_cast<uint32_t>(kH));
    tiling.set_kw(static_cast<uint32_t>(kW));
    tiling.set_ho(static_cast<uint32_t>(Ho));
    tiling.set_wo(static_cast<uint32_t>(Wo));

    tiling.set_strideH(static_cast<uint32_t>(sH));
    tiling.set_strideW(static_cast<uint32_t>(sW));
    tiling.set_padTop(static_cast<uint32_t>(pT));
    tiling.set_padLeft(static_cast<uint32_t>(pL));
    tiling.set_padBottom(static_cast<uint32_t>(pB));
    tiling.set_padRight(static_cast<uint32_t>(pR));
    tiling.set_dilationH(static_cast<uint32_t>(dH));
    tiling.set_dilationW(static_cast<uint32_t>(dW));
    tiling.set_groups(static_cast<uint32_t>(G));

    tiling.set_totalOutElems(totalOutElems);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaces = context->GetWorkspaceSizes(1);
    workspaces[0] = 0;

    return ge::GRAPH_SUCCESS;
}

